import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limiting the size of the buffer to avoid buffer overflow
        int bufferSize = Math.min(input.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copying user input into the buffer with bounds checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer overflow vulnerability successfully mitigated!");
    }
}

